  <text x="20" y="32" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">州別税率比較 — ノースカロライナ vs ケンタッキー</text>
  <g font-family="sans-serif">
    <line x1="60" y1="320" x2="660" y2="320" stroke="#3f3f46" stroke-width="1.5"/>
    <rect x="110" y="263" width="130" height="57" rx="6" fill="#38bdf8"/>
    <text x="175" y="253" fill="#e4e4e7" font-size="16" text-anchor="middle" font-weight="700">6%</text>
    <text x="175" y="342" fill="#a1a1aa" font-size="13" text-anchor="middle">NC予測市場(無規制)</text>
    <rect x="290" y="184" width="130" height="136" rx="6" fill="#f59e0b"/>
    <text x="355" y="174" fill="#e4e4e7" font-size="16" text-anchor="middle" font-weight="700">14.25%</text>
    <text x="355" y="342" fill="#a1a1aa" font-size="13" text-anchor="middle">ケンタッキー予測市場(係争中)</text>
